using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "McpWebServer", Version = "1.0.0" };
    options.ServerInstructions = "An MCP server exposing tools and configuration resources over HTTP.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();                          // Streamable HTTP at /mcp
app.MapGet("/health", () => "ok");     // Health check for orchestrators

app.Run();

